1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	  moonstone: 25,
9	};
10	
11	type Item = { type: string; cursed?: boolean };
12	type Step = { type: string; items: Item[] };
13	
14	const BLOCK_OF_3_PRICE = 60;
15	
16	const COMPONENT_TYPES = ["rune", "moonstone"];
17	
18	function countByType(items: Item[]): Record<string, number> {
19	  const counts: Record<string, number> = {};
20	  for (const item of items) {
21	    counts[item.type] = (counts[item.type] ?? 0) + 1;
22	  }
23	  return counts;
24	}
25	
26	function priceForType(type: string, count: number): number {
27	  if (COMPONENT_TYPES.includes(type) && count === 3) {
28	    return BLOCK_OF_3_PRICE;
29	  }
30	  return count * BASE_PREMIUM_BY_TYPE[type];
31	}
32	
33	function itemPremium(item: Item): number {
34	  let premium = BASE_PREMIUM_BY_TYPE[item.type];
35	  if (item.cursed) {
36	    premium *= 1.5;
37	  }
38	  return premium;
39	}
40	
41	function cursedPremium(items: Item[]): number {
42	  return items
43	    .filter((item) => item.cursed)
44	    .reduce((total, item) => total + itemPremium(item), 0);
45	}
46	
47	function plainPremium(items: Item[]): number {
48	  const counts = countByType(items.filter((item) => !item.cursed));
49	  return Object.entries(counts).reduce(
50	    (total, [type, count]) => total + priceForType(type, count),
51	    0,
52	  );
53	}
54	
55	function basePremium(items: Item[]): number {
56	  return cursedPremium(items) + plainPremium(items);
57	}
58	
59	export function runScenario(steps: Step[]): unknown[] {
60	  return steps.map((step) => ({
61	    premium: PROCESSING_FEE + basePremium(step.items),
62	  }));
63	}
